import uuid = require('uuid');
import * as path from 'path';
import * as events from 'events';
import { TimeUtils } from 'jibo-cai-utils';
import { DOFSet } from 'animation-utilities';
import { AnimationInstance, AnimationState } from 'jibo-expression-client';
import { BuilderLayer, AnimConfig, Transform } from './Classes';
import { Animation } from './Animation';
import { AUDIO_ONLY_META } from './AnimUtils';

import parentLog from './log';
const log = parentLog.createChild("Playback");

import JiboNS = require('../../jibo');  // NOTE: Only for type declaration, not runtime dependency
type KeysAnimation = JiboNS.rendering.animation.KeysAnimation;
type KeysData = JiboNS.rendering.animation.KeysData;


const FRAMERATE = 30;
const defaultOptions: PlaybackOptions = {
    ownerInformation: 'AnimDB',
    disableSetFaceAnim: false,
    screenCenterOverride: true
};


/**
 * @interface jibo.animdb.PlaybackResult
 * @description Interface for the result of Play on an Animation.
 * @property playback {jibo.animdb.Playback} Playback object created to play the animation.
 * @property result {Promise<AnimationState>} Resulting state the animation completed playback in.
 */
export interface PlaybackResult {
    playback: Playback;
    result: Promise<AnimationState>;
}


/**
 * @interface jibo.animdb#PlaybackOptions
 * @description Interface of playback options.
 * @property [forceReturnToIdle] {boolean} `true` to return Jibo to neutral pose after the animation finishes.
 * @property [screenCenterOverride] {boolean} `true` to center screen content before the animation plays.
 * @property [ownerInformation] {string} Name by which the DOFArbiter should track the requester.
 * @property [disableSetFaceAnim] {boolean} Disables setting animation as the jibo.face.animation
 */
export interface PlaybackOptions {
    forceReturnToIdle?: boolean;
    screenCenterOverride?: boolean;
    ownerInformation?: string;
    disableSetFaceAnim?: boolean;
}


class ExtPromise<T> {

    resolve: (d?: T) => any;
    reject: (err?: any) => any;
    promise: Promise<T>;

    constructor() {
        this.promise = new Promise<T>((res, rej) => {
            this.resolve = res;
            this.reject = rej;
        });
    }
}


/**
 * @class Playback
 * @memberof jibo.animdb
 */
export class Playback extends events.EventEmitter {

    private static DOFS_TO_CENTER: DOFSet;

    public playbackPr: Promise<Playback>;
    public instance: AnimationInstance;

    public duration: number;
    public speed: number;

    private jibo: typeof JiboNS;
    private playExtPr: ExtPromise<AnimationState>;
    private keysAnimation: KeysAnimation;
    private config: AnimConfig;
    private options: PlaybackOptions;
    private filePath: string;
    private runtimeKeys: boolean = false;
    //need to fix Jibo's loader typings so that jibo.loader is a namespace
    private assetToken: any;
    private hasScreenDOFs: boolean;
    private holdSafeDuration: number = 0;
    private hasBeenStopped: boolean;

    /**
     * Creates a playback object
     */
    constructor(private transform: Transform, private cacheName: string, private animation: Animation) {
        super();
        this.runtimeKeys = !this.animation.meta.path;
        this.jibo = this.animation.parent.parent.jibo;
    }

    /**
     * Initializes the KeysPlayback object for the animation.
     *
     * @method jibo.animdb.Playback#init
     * @param {jibo.animdb#AnimConfig} config - Config that allow configuring creation of animation.
     * @returns {Promise<jibo.animdb.Playback>}
     */
    async init(config: AnimConfig): Promise<Playback> {
        this._init(config);  // Mutates config and places on this.config!
        this.keysAnimation = await this.loadAnimation();
        this.instance = this.keysAnimation.instance;
        log.debug(`Initialized playback  ${this.animation.name}`);
        return this;
    }

    /**
     * Initializes the KeysPlayback object for the animation and immediately plays it.
     *
     * @method jibo.animdb.Playback#initAndPlay
     * @param {jibo.animdb#AnimConfig} config - Config that allow configuring creation of animation.
     * @param {jibo.animdb#PlaybackOptions} [options] - Options that allow configuring playback of animation.
     * @returns {Promise<AnimationState>}
     */
    async initAndPlay(config: AnimConfig, options?: PlaybackOptions): Promise<AnimationState> {
        this.playExtPr = new ExtPromise<AnimationState>();
        this._init(config);  // Mutates config and places on this.config!
        this.resolvePlaybackOptions(options);  // Mutates options and places on this.options!
        // We load the animation from cache (or use provided animation data)
        this.keysAnimation = await this.loadAnimation(true);
        this.instance = this.keysAnimation.instance;
        this.registerEventsAndHandlers();
        const state = await this.playExtPr.promise;
        await this.handlePlaybackCompletion(state);
        return state;
    }

    /**
     * Plays the animation
     *
     * @method jibo.animdb.Playback#play
     * @param {jibo.animdb#PlaybackOptions} [options] - Options that allow configuring playback of animation
     * @returns {Promise<AnimationState>}
     */
    async play(options?: PlaybackOptions): Promise<AnimationState> {
        this.playExtPr = new ExtPromise<AnimationState>();
        this.resolvePlaybackOptions(options);  // Mutates options and places on this.options!
        this.registerEventsAndHandlers();

        // Here, if this animation has screen content and a centering of the screen DOFs was explicitly requested, we center all of the screen DOFs
        if ((this.options.screenCenterOverride === false) && this.hasScreenDOFs) {
            try {
                await this.jibo.expression.centerRobot({
                    requestor: this.options.ownerInformation,
                    centerGlobally: false,
                    dofs: this.jibo.expression.dofs.SCREEN
                });
            } catch (err) {
                this.playExtPr.reject(err);
            }
        }
        try {
            if (!this.hasBeenStopped) {
                log.debug(`Playback  ${this.animation.name}  playing with these options: `, this.options);
                await this.keysAnimation.instance.play(this.options.ownerInformation);
            }
        } catch (err) {
            this.playExtPr.reject(err);
        }
        const state = await this.playExtPr.promise;
        await this.handlePlaybackCompletion(state);
        return state;
    }

    /**
     * Stops playing animation
     *
     * @method jibo.animdb.Playback#stop
     * @returns {Promise<void>}
     */
    async stop(): Promise<void> {
        if (this.keysAnimation) {
            try {
                await this.keysAnimation.instance.stop();
            } catch (error) {
                log.warn(`Could not stop instance that no longer exists: `, error);
            }
        }
        //make real sure that we are cleaning up the keys data
        if (this.assetToken) {
            this.assetToken.unload();
            this.assetToken = null;
        }
    }

    /**
     * !Mutates!
     * Actually initializes the KeysPlayback object for the animation.
     *
     * @method jibo.animdb.Playback#_init
     * @param {jibo.animdb#AnimConfig} config - Config that allow configuring creation of animation
     * @private
     */
    private _init(config: AnimConfig) {
        if (!config) {
            config = {
                cache: this.jibo.loader.activeCache
            };
        }
        log.debug(`Initializing playback  ${this.animation.name}  with config: `, config);

        if (this.runtimeKeys) {
            this.filePath = this.animation.resourceRoot;
        } else {
            this.filePath = path.join(this.animation.resourceRoot, this.animation.meta.path);
        }

        // Do animation configuration (such as scaling, orientation, layer, etc.)

        if (this.animation.meta.metaTerms.indexOf(AUDIO_ONLY_META) !== -1) {
            config.layer = BuilderLayer.BEAT;
        }

        // If we should flip the orientation or exaggerate his motions
        if (this.transform.shouldFlipLeftRight || this.transform.exaggerate) {
            let flipMult = this.transform.shouldFlipLeftRight ? -1 : 1;
            let flipAndExagMult = flipMult * (this.transform.exaggerate || 1);
            if ((flipMult !== 1) || (flipAndExagMult !== 1)) {
                let dofs = {
                    bottomSection_r: 1,
                    middleSection_r: 1,
                    topSection_r: 1,
                    eyeSubRootBn_t: 1
                };
                Object.keys(dofs).forEach(dof => {
                    if (dof === "eyeSubRootBn_t_2") {
                        dofs[dof] *= flipMult;
                    } else {
                        dofs[dof] *= flipAndExagMult;
                    }
                });
                config.scale = dofs;
            }
        }

        // Calculate Hold Safe Duration
        if (this.transform.framesToHold !== -1) {
            this.holdSafeDuration = ((this.transform.framesToHold / FRAMERATE) * 1000);
        }

        // Calculate speed
        if (this.transform.speed !== 1) {
            config.speed = this.transform.speed;
        }

        // Calculate duration (not sent to loader)
        this.duration = this.animation.meta.duration;
        if (this.transform.speed !== -1) {
            this.duration *= this.transform.speed;
        }
        if (this.transform.framesToHold !== -1) {
            this.duration += this.transform.framesToHold;
        }

        this.config = config;
    }

    /**
     * !Mutates!
     * Merges default Playback options with those provided,
     *
     * @method jibo.animdb.Playback#resolvePLaybackOptions
     * @param {jibo.animdb#PlaybackOptions} options
     * @private
     */
    private resolvePlaybackOptions(options: PlaybackOptions) {
        // We put together our KeysPlaybackOptions
        const playOptions = Object.assign({}, defaultOptions, options);
        this.options = playOptions;
    }

    /**
     * !Mutates!
     * Registers all handlers to all relevant events on the keysAnimation
     *
     * @method jibo.animdb.Playback#registerEventsAndHandlers
     * @private
     */
    private registerEventsAndHandlers() {
        // Check if this animation has any screen content
        const dofsInScreen = this.jibo.expression.dofs.SCREEN;
        const dofsInAnim = this.keysAnimation.instance.dofs;
        const dofsNotInAnim = dofsInScreen.minus(dofsInAnim);
        this.hasScreenDOFs = (dofsNotInAnim.getDOFs().length !== dofsInScreen.getDOFs().length);

        // TODO: Switch to system proposed in https://jira.jibo.com/browse/SB-2957 when available
        if (this.hasScreenDOFs && !this.options.disableSetFaceAnim) {
            this.jibo.face.eye.addAnimation(this.keysAnimation);
        }

        const stopHandler = (state: AnimationState) => {
            this.hasBeenStopped = true;
            log.debug(`Playback  ${this.animation.name}  was stopped with state  ${state}`);
            this._cleanup();
            this.playExtPr.resolve(state);
        };

        const holdSafeHandler = async () => {
            try {
                if (this.keysAnimation) {
                    await this.keysAnimation.instance.pause();
                    await TimeUtils.wait(this.holdSafeDuration);
                }
                if (this.keysAnimation) {
                    await this.keysAnimation.instance.resume();
                }
            } catch (error) {
                log.warn(`Error in hold-safe logic for animation  ${this.animation.name}: `, error);
            }
        };

        this.keysAnimation.instance.events.stopped.on(() => stopHandler(AnimationState.STOPPED));
        this.keysAnimation.instance.events.cancelled.on(() => stopHandler(AnimationState.CANCELLED));
        this.keysAnimation.instance.events.rejected.on(() => stopHandler(AnimationState.REJECTED));

        if (this.holdSafeDuration > 0) {
            this.keysAnimation.instance.events.holdSafe.on(holdSafeHandler);
        }
    }

    /**
     * When an animation completes, handle returning body to neutral, etc.
     *
     * @method jibo.animdb.Playback#handlePlaybackCompletion
     * @param {AnimationState} state
     * @private
     */
    private async handlePlaybackCompletion(state: AnimationState) {
        if (state === AnimationState.REJECTED) {
            log.warn(`Playback  ${this.animation.name}  was rejected! (See DOFArbiter debug for more details)`);
        }
        // We don't have to return to idle after rejection since we never really moved
        else if (this.options.forceReturnToIdle) {
            log.debug(`Returning playback  ${this.animation.name}  to idle pose.`);
            // We fully return to neutral (except the BASE and EYE_TRANSLATE DOFs, to play nicely with Attention)
            if (!Playback.DOFS_TO_CENTER) {
                const dofs = this.jibo.expression.dofs;
                Playback.DOFS_TO_CENTER = dofs.ALL.minus(dofs.BASE).minus(dofs.EYE_TRANSLATE);
            }
            await this.jibo.expression.centerRobot({
                requestor: this.options.ownerInformation,
                dofs: Playback.DOFS_TO_CENTER,
                centerGlobally: false
            });
        }
    }

    /**
     * Clean-up after a played animation
     *
     * @method jibo.animdb.Playback#_cleanup
     * @private
     */
    private _cleanup(): void {
        if (this.keysAnimation) {
            if (this.hasScreenDOFs && !this.options.disableSetFaceAnim) {
                this.jibo.face.eye.removeAnimation(this.keysAnimation);
            } else {
                this.keysAnimation.destroy();
            }
            this.keysAnimation = null;

            // If the keys data has not already been unloaded, unload it
            if (this.assetToken) {
                this.assetToken.unload();
                this.assetToken = null;
            }
        }
        this.instance = null;
    }

    /**
     * Loads the animation data from disk and optionally immediately plays
     *
     * @method jibo.animdb.Animation#loadAnimation
     * @param {boolean} [andPlay=false] Immediately play the animation upon loading (if possible)
     * @returns {Promise<KeysAnimation>} The jibo runtime KeysAnimation object
     * @private
     */
    private async loadAnimation(andPlay=false): Promise<KeysAnimation> {
        const id:string = this.filePath;
        // If a runtime keys, then generate a random id to avoid cache collisions
        if (this.runtimeKeys) {
            this.filePath = path.join(id, uuid.v4());
        }

        return new Promise<KeysAnimation>((resolve, reject) => {
            const load = this.jibo.loader.load({
                id: id,
                cache: this.cacheName,
                options: this.config,
                data: this.runtimeKeys ? this.animation.animData : null,
                src: this.filePath,
                upload: true,
                root: this.animation.resourceRoot,
                type: 'keys',
            } as any,
            (error, keysData:KeysData) => {
                if (error) {
                    reject(error);
                } else {
                    // if assetToken is null, we were stopped before playback, don't instantiate an animation
                    if (!this.assetToken) {
                        return;
                    }
                    if (andPlay && this.options) {
                        resolve(keysData.getAndPlayAnim(Object.assign({ src: this.filePath }, this.config), this.options.ownerInformation));
                    } else {
                        resolve(keysData.getAnim(Object.assign({ src: this.filePath }, this.config)));
                    }
                }
            });
            this.assetToken = load.tokens[0];
        });
    }
}
