import { Animation } from './Animation';
import { Category } from './Category';
import { Utils } from './Utils';
import { AnimQuery, AnimResults, SearchResults } from './Classes';
import { AnimUtils } from './AnimUtils';
import { AnimDB } from "./AnimDB";

/**
 * @class AnimCollection
 * @memberof jibo.animdb
 */
export class AnimCollection {
    public animations: Animation[] = [];
    public categories: Category[] = [];

    private _animationsByName: Map<string, Animation>;
    private _categoriesByName: Map<string, Category>;

    constructor(public parent: AnimDB) {
        this._animationsByName = new Map<string, Animation>();
        this._categoriesByName = new Map<string, Category>();
    }

    /**
     * Adds animation to collection
     * @method jibo.animdb.AnimCollection#addAnimation
     * @param {jibo.animdb.Animation} animation Animation to add
     */
    addAnimation(animation: Animation) {
        const nameLower = animation.name.toLowerCase();
        if (!this._animationsByName.has(nameLower)) {
            this._animationsByName.set(nameLower, animation);
            this.animations.push(animation);
        }
    }

    /**
     * Adds animation category to collection
     * @method jibo.animdb.AnimCollection#addCategory
     * @param {jibo.animdb.Category} category Category to add
     */
    addCategory(category: Category) {
        const nameLower = category.name.toLowerCase();
        if (!this._categoriesByName.has(nameLower)) {
            this._categoriesByName.set(nameLower, category);
            this.categories.push(category);
        }
    }

    /**
     * Returns category by name
     * @method jibo.animdb.AnimCollection#getCategoryByName
     * @param {string} name Name of category
     * @returns {jibo.animdb.Category|undefined}
     */
    getCategoryByName(name: string): Category {
        return this._categoriesByName.get(name.toLowerCase());
    }

    /**
     * Returns animation by name
     * @method jibo.animdb.AnimCollection#getAnimByName
     * @param {string} name Name of animation
     * @returns {jibo.animdb.Animation|undefined}
     */
    getAnimByName(name: string): Animation {
        return this._animationsByName.get(name.toLowerCase());
    }

    /**
     * Returns the animation names in this collection.
     * @method jibo.animdb.AnimCollection#getAnimationNames
     * @returns {string[]} List of animation names.
     */
    getAnimationNames() {
        return Array.from(this._animationsByName.keys());
    }

    /**
     * Returns the animation categories in this collection.
     * @method jibo.animdb.AnimCollection#getAnimationCategories
     * @returns {string[]} List of animation categories.
     */
    getAnimationCategories() {
        return Array.from(this._categoriesByName.keys());
    }

    /**
     * Search animations for meta tags
     * @method jibo.animdb.AnimCollection#search
     * @param {string} searchTerm Search term could be meta tag, name, or category
     * @returns {jibo.animdb.SearchResults}
     */
    search(searchTerm: string): SearchResults {
        let term = searchTerm.toLowerCase();
        let res = new SearchResults();
        this._search(term, res);
        return res;
    }

    /**
     * Queries for animations that fit the criteria
     * @method jibo.animdb.AnimCollection#query
     * @param {jibo.animdb#AnimQuery} query
     * @return {jibo.animdb.AnimResults}
     */
    query(query: AnimQuery): AnimResults {
        AnimUtils.insertDefaultAnimQueryParams(query);

        let res = new AnimResults();
        this._query(query, res);

        let matchingNoDupes = [];
        new Set(res.matching).forEach(elm => matchingNoDupes.push(elm));
        res.matching = matchingNoDupes;

        let nonMatchingNoDupes = [];
        new Set(res.nonMatching).forEach(elm => nonMatchingNoDupes.push(elm));
        res.nonMatching = nonMatchingNoDupes;

        return res;
    }

    /**
     * @private
     */
    _search(term: string, res: SearchResults): void {
        let catByName = this._categoriesByName.get(term);
        if (catByName) {
            res.category = catByName;
        }

        let animByName = this._animationsByName.get(term);
        if (animByName) {
            res.name = animByName;
        }

        this.animations.forEach( anim => {
            anim.meta.metaTerms.forEach( meta => {
                if (meta === term) {
                    res.meta.push(anim);
                }
            });
        });
    }

    /**
     * @private
     */
    _query(query: AnimQuery, res: AnimResults) {
        if (query.categories.length) {
            query.categories.forEach( catName => {

                let category = this._categoriesByName.get(catName);
                if (category) {
                    category._query(query, res);
                }
            });
        }
        else {
            Utils.getAnimationsByQuery(this.animations, res, query);
        }
    }
}
