/*
 * API variables
 */

/**
 * The singleton animDB instance
 * Should not be used in normal operation, but made visible for testing and debugging purposes
 * @type {AnimDB}
 * @private
 */
export let _animDB: AnimDB;

/*
 * API methods
 */

/**
 * Creates an animDB from a list of root directories
 * @method jibo.animdb#readAnimDB
 * @param {object} jibo - The jibo runtime
 * @param {string} [animDBPath] Path to an animDB json
 * @param {string[]} [moreAnimDBPaths] Paths to more animDB json files
 * @returns {Promise<jibo.animdb.AnimDB>}
 */
export async function init(jibo: any, animDBPath?: string, ...moreAnimDBPaths: string[]): Promise<void> {
    if (!animDBPath) {
        _animDB = new AnimDB(jibo);
    } else {
        _animDB = await AnimDBParser.readAnimDB(jibo, animDBPath, ...moreAnimDBPaths);
    }
}

/**
 * Checks if AnimDB is already initialized
 * @method jibo.animdb#isInitialized
 * @returns {boolean}
 */
export function isInitialized(): boolean {
    return !!_animDB;
}

/**
 * Finds AnimDB database path globally or from directory
 * @method jibo.animdb#resolveAnimDB
 * @param {object} jibo - The jibo runtime
 * @param {string} [dir] - Optional directory to search from; searches globally if not provided
 * @returns {string} Path to AnimDB Database globally or from directory
 */
export function resolveAnimDB(jibo: any, dir?: string): string {
    let animDBPath: string;
    let packjson: any;

    if (!dir) {
        const adaPath = jibo.utils.PathUtils.resolve('jibo-anim-db-animations');
        dir = adaPath ? path.dirname(adaPath) : undefined;
    }

    try {
        packjson = require(path.resolve(dir, 'package.json'));
    } catch (error) {
        return undefined;
    }

    if (packjson && packjson.jibo) {
        if (packjson.jibo.animdb && (path.extname(packjson.jibo.animdb).toLowerCase() === '.json')) {
            animDBPath = path.resolve(dir, packjson.jibo.animdb);
        } else {
            // Fallback to old-style before path in package.json
            animDBPath = path.resolve(dir, 'animdb.json');
        }
    }

    if (fs.existsSync(animDBPath)) {
        return animDBPath;
    }
    return undefined;
}

/**
 * Get animation by name. Returns first animation by that iname in the case of multiple collections
 * @method jibo.animdb#getAnimByName
 * @param {string} animName Name of animation to retrieve
 * @returns {jibo.animdb.Animation}
 */
export function getAnimByName(animName: string): Animation {
    return _animDB.getAnimByName(animName);
}

/**
 * Get animation names. Returns a list of the animation names in the animDB.
 * @method jibo.animdb#getAnimationNames
 * @returns {string[]} List of animation names
 */
export function getAnimationNames(): string[] {
    return _animDB.getAnimationNames();
}

/**
 * Get animation categories. Returns a list of the animation categories in the animDB.
 * @method jibo.animdb#getAnimationCategories
 * @returns {string[]} List of animation categories
 */
export function getAnimationCategories(): string[] {
    return _animDB.getAnimationCategories();
}

/**
 * Search animations for meta tags
 * @method jibo.animdb#search
 * @param {string} searchTerm Search term could be meta tag, name, or category
 * @returns {jibo.animdb.SearchResults}
 */
export function search(searchTerm: string): SearchResults {
    return _animDB.search(searchTerm);
}

/**
 * Queries for animations that fit the criteria
 * @method jibo.animdb#query
 * @param {jibo.animdb#AnimQuery} query The query parameters
 * @return {jibo.animdb.AnimResults}
 */
export function query(query: AnimQuery): AnimResults {
    return _animDB.query(query);
}

/**
 * Adds animation database instance
 * @method jibo.animdb#push
 * @param {jibo.animdb.AnimCollection} animCollection Animation collection to add
 */
export function push(animCollection: AnimCollection): void {
    _animDB.push(animCollection);
}

/**
 * Pops the last anim database instance off the stack
 * @method jibo.animdb#pop
 * @return {jibo.animdb.AnimCollection}
 */
export function pop(): AnimCollection {
    return _animDB.pop();
}
