import * as path from 'path';
import * as fs from 'fs';
import { FileUtils, PromiseUtils } from 'jibo-cai-utils';
import { Anim } from './animation_formats/0_6_X/AnimV0_6_X';
import { AnimDB } from './AnimDB';
import { AnimCollection } from './AnimCollection';
import { Animation } from './Animation';
import { Category } from './Category';
import { AnimUtils, AUDIO_ONLY_META } from './AnimUtils';
import { Utils } from './Utils';
import { LayerName, LayerPresence, AnimMetadata } from './Classes';
import { INFINITE_DURATION } from './Range';

const stringify = require('json-stable-stringify');


/**
 * @typedef jibo.animdb.AnimDBParser#AnimMetadataMap
 * @description Map of AnimDB names to their {@link jibo.animdb#AnimMetadata}.
 */
export type AnimMetadataMap = { [x: string]: AnimMetadata };


/**
 * @typedef jibo.animdb.AnimDBParser#KeyValueAnimMetadataArray
 * @description Array of Key/Value Pairs of AnimDB names to their {@link jibo.animdb#AnimMetadata}.
 */
export type KeyValueAnimMetadataArray = [string, AnimMetadata][];


/**
 * @class AnimDBParser
 * @memberof jibo.animdb
 * @intdocs
 */
export class AnimDBParser {

    /**
     * Creates an animDB from a list of root directories
     * @method jibo.animdb.AnimDBParser#readAnimDB
     * @param {object} jibo - The jibo runtime
     * @param {string} animDBPath - Path to an animDB json
     * @param {string[]} [moreAnimDBPaths] - Paths to more animDB json
     * @returns {Promise<jibo.animdb.AnimDB>}
     */
    static readAnimDB(jibo: any, animDBPath: string, ...moreAnimDBPaths: string[]): Promise<AnimDB> {
        moreAnimDBPaths.unshift(animDBPath);

        let animDB = new AnimDB(jibo);

        let promises = moreAnimDBPaths.map( (rootDir) => {
            return AnimDBParser.readAndAddAnimCollection(animDB, rootDir);
        });

        return Promise.all(promises)
            .then(() => animDB);
    }

    /**
     * Creates an animDB instance from a particular root animation directory
     * @method jibo.animdb.AnimDBParser#readAndAddAnimCollection
     * @param {jibo.animdb.AnimDB} animDB - The animDB to add collection to
     * @param {string} animDBPath - Path to an animDB json
     * @returns {Promise<void>}
     */
    static readAndAddAnimCollection(animDB: AnimDB, animDBPath: string): Promise<void> {
        const rootDir = path.dirname(animDBPath);

        return FileUtils.readFile(animDBPath)
            .then(animStr => {
                const animMetaMap: AnimMetadataMap = JSON.parse(animStr);
                AnimDBParser.addAnimCollection(animDB, rootDir, animMetaMap);
            });
    }

    /**
     * Adds an animation collection to a supplied animDB instance
     * @method jibo.animdb.AnimDBParser#addAnimCollection
     * @param {jibo.animdb.AnimDB} animDB - The animDB to add collection to
     * @param {string} rootDir - Root directory for Animations in the collection
     * @param {jibo.animdb.AnimDBParser#AnimMetadataMap} animMetaMap - Data comprising the collection to be added.
     */
    static addAnimCollection(animDB: AnimDB, rootDir: string, animMetaMap: AnimMetadataMap): void {
        let collection = new AnimCollection(animDB);
        AnimDBParser.addToAnimCollection(collection, rootDir, animMetaMap);
        animDB.push(collection);
    }

    /**
     * Adds a collection of AnimMetadata to a supplied animation collection
     * @method jibo.animdb.AnimDBParser#addToAnimCollection
     * @param {jibo.animdb.AnimDB} animDB - The animDB to add collection to
     * @param {string} rootDir - Root directory for Animations in the collection
     * @param {jibo.animdb.AnimDBParser#KeyValueAnimMetadataArray|jibo.animdb.AnimDBParser#AnimMetadataMap} animMetadataCollection - Data comprising the collection to be appended.
     */
    static addToAnimCollection(collection: AnimCollection, rootDir: string, animMetadataCollection: KeyValueAnimMetadataArray | AnimMetadataMap) {
        let kvAnimMetaArray: KeyValueAnimMetadataArray;
        if (animMetadataCollection instanceof Array) {
            kvAnimMetaArray = animMetadataCollection;
        } else {
            kvAnimMetaArray = [];
            Object.keys(animMetadataCollection).forEach(key => {
                kvAnimMetaArray.push([key, animMetadataCollection[key]]);
            });
        }
        for (let [animName, animMeta] of kvAnimMetaArray) {
            if (!animMeta.name) {
                throw new Error(`Missing anim name: ${animName}`);
            }
            animName = animMeta.name.toLowerCase();
            const anim = new Animation(collection, animMeta, rootDir);

            let existingAnim = collection.getAnimByName(anim.name);
            if (existingAnim) {
                const paths = [existingAnim.meta.path, animMeta.path];
                throw new Error(`Duplicate animation name: '${animName}' at paths: ${paths}`);
            }
            collection.addAnimation(anim);

            anim.meta.categories.forEach(categoryName => {
                let cat = collection.getCategoryByName(categoryName);
                if (!cat) {
                    cat = new Category(categoryName);
                    collection.addCategory(cat);
                }
                cat.addAnimation(anim);
            });
        }
    }

    /**
     * Finds all key files under a certain root dir (recursively), reads them and
     * extracts meta data from them.
     * Writes resulting metadata collection to a json object on disk
     * @method jibo.animdb.AnimDBParser#createAndWriteAnimMetaData
     * @param {Object} jibo - The jibo runtime
     * @param {string} rootDir - Animations will be searched in rootDir/animations
     * @param {string} outName - Name of output file (no extension)
     * @returns {Promise<any>}
     */
    static createAndWriteAnimMetaData(jibo: any, rootDir: string, outName: string): Promise<any> {
        return AnimDBParser.createAnimMetaData(jibo, rootDir)
            .then( allAnimData => {
                const outPath = path.join(rootDir, outName + '.json');
                const outData = stringify(allAnimData, { space: '  ' });
                return PromiseUtils.promisify( h => fs.writeFile(outPath, outData, 'utf8', h) );
            });
    }

    /**
     * Finds all key files under a certain root dir (recursively), reads them and
     * extracts meta data from them
     * @method jibo.animdb.AnimDBParser#createAnimMetaData
     * @param {Object} jibo - The jibo runtime
     * @param {string} rootDir - Animations will be searched in rootDir/animations
     * @returns {Promise<jibo.animdb.AnimDBParser#AnimMetadataMap>}
     */
    static createAnimMetaData(jibo: any, rootDir: string): Promise<AnimMetadataMap> {
        const animsDir = path.join(rootDir, 'animations');

        return FileUtils.findAllFilesWithExt(animsDir, 'keys')
            .then((filePaths) => {
                const goodPaths = filePaths.filter(filePath => {
                    const relFilePath = path.relative(animsDir, filePath);
                    const pathElements = relFilePath.split(path.sep);
                    return !pathElements.some(el => el.startsWith('_'));
                });
                return AnimDBParser._createAnimMetaData(jibo, rootDir, goodPaths);
            });
    }

    /**
     * Reads supplied list of Keys paths and extracts AnimMetadata from them
     * @method jibo.animdb.AnimDBParser#_createAnimMetaData
     * @param {Object} jibo - The jibo runtime
     * @param {string} rootDir - Root directory for animation paths
     * @param {string[]} paths - Animations paths that will be parsed and extracted from
     * @returns {Promise<jibo.animdb.AnimDBParser#AnimMetadataMap>} An object comprised of {@link jibo.animdb#AnimMetadata}.
     * @intdocs
     */
    static async _createAnimMetaData(jibo: any, rootDir: string, paths: string[]): Promise <AnimMetadataMap> {

        // Cache jibo's current animDB and temporarily set it to a blank one
        let cachedAnimDB = jibo.animDB._animDB;
        jibo.animDB._animDB = new AnimDB(jibo);

        // Make our single temp AnimCollection that we will constantly add to
        let collection = new AnimCollection(jibo.animDB._animDB);
        jibo.animDB.push(collection);

        // Due to named references, we cannot resolve all animations at once, but rather load them across multiple passes.
        // That is, keys that contain named references can't be loaded/resolved until the referencd keys exists in the DB
        let completeMetadata: AnimMetadataMap = {};
        let unparsed: string[] = [];
        let parsed: AnimMetadata[] = [];
        while (paths.length > 0) {
            const unparsedCount = paths.length;

            // Here we load and parse all the animations in sequence
            // We used to do it in parallel but it could result in too many open file descriptors
            for (const path of paths) {
                try {
                    const meta = await AnimDBParser.parseAnimation(jibo, path, rootDir);
                    parsed.push(meta);
                } catch (err) {
                    if (err instanceof ReferenceError) {  // If it contains an unresolvable name reference, try again in the next pass
                        unparsed.push(path);
                    } else {
                        throw err;
                    }
                }
            }

            // If the number of unresolvavle animations stays constant over multiple passes, there is a circular dependency, so we stop (such keys would have to be maliciously made)
            if (unparsedCount === unparsed.length) {
                throw new Error(`Could not resolve ${unparsedCount} animations: ${unparsed}`);
            } else {
                paths = unparsed;
            }

             // Here we fix the paths to be relative to rootDir
            const rootDirResolved = path.resolve(rootDir);

            // Build a KeyValue Array of all AnimName to AnimMetadata for adding to our ongoing collection
            let kvAnimMetaArray: KeyValueAnimMetadataArray = [];
            parsed.forEach(animData => {
                const firstPart = animData.path.substring(0, rootDirResolved.length);
                if (firstPart !== rootDirResolved) {
                    throw new Error(`Animation doesn't have the expected root path: ${[animData.path, rootDirResolved]}`);
                }
                animData.path = animData.path.substring(rootDirResolved.length + path.sep.length);
                kvAnimMetaArray.push([animData.name, animData]);
            });
            AnimDBParser.addToAnimCollection(collection, rootDir, kvAnimMetaArray);

            // Convert the KeyValue Array into a Map and add it to our ongoing metadata store -- what we write out when building AnimDBs
            // This is separate and paralell to the AnimDB's collection, which is created and added to in order to resolve named references
            let tempAnimMetaMap: AnimMetadataMap = {};
            kvAnimMetaArray.forEach(([key, value]: [string, AnimMetadata]) => {
                tempAnimMetaMap[key] = value;
            });
            Object.assign(completeMetadata, tempAnimMetaMap);

            parsed = [];
            unparsed = [];
        }

        jibo.animDB._animDB = cachedAnimDB;
        return completeMetadata;
    }


    /**
     * Loads animation data from disk and calculates derived properties
     * @method jibo.animdb.AnimDBParser#parseAnimation
     * @param {Object} jibo - The jibo runtime
     * @param {string} filePath Path to animation
     * @param {string} [rootDir] Root directory of animation
     * @returns {Promise<jibo.animdb#AnimMetadata>}
     */
    static async parseAnimation(jibo: any, filePath: string, rootDir?: string): Promise<AnimMetadata> {
        const animData = await AnimDBParser.loadKeys(jibo, filePath, rootDir);
        return AnimDBParser.parseAnimationFromAnim(animData, filePath);
    }

    /**
     * Loads animation data from disk and expanding resolving/"macro-expanding" any Reference layers
     * @method jibo.animdb.AnimDBParser#loadKeys
     * @param {Object} jibo - The jibo runtime
     * @param {string} keysPath Path to animation
     * @param {string} [rootDir] Root directory of animation
     * @returns {Promise<jibo.animdb#Anim>}
     */
    static async loadKeys(jibo: any, keysPath: string, rootDir?: string): Promise<Anim> {
        return new jibo.rendering.animation.KeysLoader(keysPath, rootDir).load();
    }

    /**
     * Calculates derived properties from Anim object
     * @method jibo.animdb.AnimDBParser#parseAnimationFromAnim
     * @param {jibo.animdb#Anim} animData Animation object
     * @param {string} [filePath] Keys file JSON
     * @returns {jibo.animdb#AnimMetadata}
     */
    static parseAnimationFromAnim(animData: Anim, filePath?: string): AnimMetadata {
        let animdbTag: any;
        let scale, speed, name;
        try {
            const defaultName = filePath ? path.basename(filePath, path.extname(filePath)) : 'UNKNOWN_ANIM';
            animdbTag = animData.animdb || {};

            name = Utils.parseString(animdbTag.name, defaultName);
            scale = [
                Utils.parseNumber(animdbTag.scaleMin, 1),
                Utils.parseNumber(animdbTag.scaleMax, 1) ];
            speed = [
                Utils.parseNumber(animdbTag.speedMin, 1),
                Utils.parseNumber(animdbTag.speedMax, 1) ];
        }
        catch (error) {
            throw new Error(`Error parsing animation at path '${filePath}': '${error}'`);
        }

        if ((speed[0] <= 0) || (speed[0] > speed[1])) {
            throw new Error(`Invalid speed bounds '${JSON.stringify(speed)}' for animation '${filePath}'`);
        }

        if (scale[0] > scale[1]) {
            throw new Error(`Invalid scale bounds '${JSON.stringify(scale)}' for animation '${filePath}'`);
        }

        const categoryString = animdbTag.categories || '';
        let categories = [];
        categoryString.split(',').forEach( category => {
            let catName = category.trim().toLowerCase();
            if (catName.length) {
                categories.push( catName );
            }
        });

        const metaString = animdbTag.meta || '';
        let metaTerms = [];
        metaString.split(',').forEach( _metaTerm => {
            let metaName = _metaTerm.trim().toLowerCase();
            if (metaName.length) {
                metaTerms.push( metaName );
            }
        });

        const holdSafeKF = AnimUtils.hasHoldSafe(animData, name);

        let durationRange = [
            speed[0] * animData.duration,
            speed[1] * animData.duration
        ];
        if (holdSafeKF !== -1) {
            durationRange[1] = INFINITE_DURATION;
        }

        let layers: LayerPresence = AnimUtils.checkLayers(animData);

        // If the animation if marked as 'audio-only' we are going to make the system lie about what layers it has
        // We're making the system lie due to a limitation in playing back AudioEvent only keys
        // AudioEvent-only keys cannot play, they need a body layer
        // However, in Embodied Speech we still want it to be treated as if it doesn't have a body layer (since we wil be playing it on the beat layer)
        if (metaTerms.indexOf(AUDIO_ONLY_META) !== -1) {
            Object.keys(layers).forEach(layer => {
                if (layers[layer] && (layer !== LayerName.AudioEvent.short)) {
                    layers[layer] = false;
                }
            });
        }

        // Here we determine all of the properties from the animation data
        const animMetadata: AnimMetadata = {
            name,
            scale,
            speed,
            durationRange,
            categories,
            metaTerms,
            holdSafeKF,
            path: filePath,
            duration: animData.duration,
            startsNeutral: AnimUtils.startsNeutral(animData),
            endsNeutral: AnimUtils.endsNeutral(animData),
            hasAudio: AnimUtils.hasAudio(animData),
            orientation: AnimUtils.calculateOrientation(animData),
            layers
        };
        return animMetadata;
    }
}
