import { Range } from './Range';
import { Anim } from './animation_formats/0_6_X/AnimV0_6_X';
import { Utils } from './Utils';
import { Playback, PlaybackOptions, PlaybackResult } from './Playback';
import { AnimConfig, Transform, AnimMetadata } from './Classes';
import { AnimCollection } from "./AnimCollection";

import parentLog from './log';
const log = parentLog.createChild("Animation");


/**
 * @class Animation
 * @memberof jibo.animdb
 * @description Instantiates Animation object.
 *
 * Important: Optional `animData` object will persist and mutate.
 *
 * @param {jibo.animdb.AnimCollection} parent - The animation collection this animation belongs to.
 * @param {jibo.animdb#AnimMetadata} meta Animation meta data
 * @param {string} resourceRoot Root directory for finding resources
 * @param {jibo.animdb#Anim} [animData] Optional animation data, if provided will override actual animation
 */
export class Animation {

    public name: string;
    public durationRange: Range;
    public animDataCache:{[path:string]:Anim} = {};

    constructor(public parent: AnimCollection,
                public meta: AnimMetadata,
                public resourceRoot: string,
                public animData?: Anim){
        this.name = meta.name;
        this.durationRange = new Range(meta.durationRange[0], meta.durationRange[1]);
    }

    /**
     * Create animation object from query parameters
     * @param {jibo.animdb#AnimConfig} [config={}] - Animation config options
     * @method jibo.animdb.Animation#createFromConfig
     * @returns {Promise<jibo.animdb.Playback>}
     */
    async createFromConfig(config: AnimConfig = {cache:null}): Promise<Playback> {
        log.debug(`Configuring Animation  ${this.name}  for configuration: `, config);
        let transformation = this._getTransformation(config);
        const playback = new Playback(transformation, config.cache, this);
        return playback.init(config);
    }

    /**
     * Create and immediately play animation object from query parameters and playback options
     * @param {jibo.animdb#AnimConfig} [config={}] - Animation config options.
     * @param {jibo.animdb#PlaybackOptions} [options] - Playback options.
     * @method jibo.animdb.Animation#play
     * @returns {Promise<jibo.animdb.PlaybackResult>}
     */
     play(config: AnimConfig = {cache: null}, options?: PlaybackOptions): PlaybackResult {
        log.debug(`Configuring Animation  ${this.name} with config: `, config, ` for immediate playback with options: `, options);
        let transformation = this._getTransformation(config);
        const playback = new Playback(transformation, config.cache, this);
        return {
            playback: playback,
            result: playback.initAndPlay(config, options)
        };
    }

    /**
     * Creates a transformation spec from a requirements object based on desired
     * speeds and duration, scale etc.
     * @param {jibo.animdb#AnimConfig} options
     * @returns {jibo.animdb.Transform}
     * @method jibo.animdb.Animation#_getTransformation
     * @private
     */
    private _getTransformation(options?: AnimConfig) {
        let trans = new Transform();
        if (options) {
            if (options.orientation) {
                let reqOrientation = <any> options.orientation as string;
                if (reqOrientation !== this.meta.orientation) {
                    trans.shouldFlipLeftRight = true;
                }
            }
            if (options.speed) {
                trans.speed = Utils.limitToRange(options.speed, this.meta.speed);
            }
            if (options.exaggerate) {
                trans.exaggerate = Utils.limitToRange(options.exaggerate, this.meta.scale);
            }

            // If a certain duration has been requested
            if (options.duration) {
                // If the requested duration is shorter than our min possible bound:
                if (options.duration < this.meta.durationRange[0]) {
                    // We set the speed to its lowest
                    trans.speed = this.meta.speed[0];
                }
                // If the requested duration is min than our desired speed duration
                else if (options.duration < trans.speed * this.meta.duration) {
                    trans.speed = options.duration / this.meta.duration;
                    trans.speed = Utils.limitToRange(trans.speed, this.meta.speed);
                }
                // If we have a hold safe key frame
                else if (this.meta.holdSafeKF !== -1) {
                    trans.framesToHold = options.duration - trans.speed * this.meta.duration;
                }
                // If the requested duration is higher than the desired speed duration
                else if (options.duration > trans.speed * this.meta.duration) {
                    // If a certain speed was not set we can set the speed
                    if (typeof options.speed !== 'number') {
                        trans.speed = options.duration / this.meta.duration;
                        trans.speed = Utils.limitToRange(trans.speed, this.meta.speed);
                    }
                }
            }
        }

        return trans;
    }
}
